import anthropic
import json

client = anthropic.Anthropic()

tools = [
    {
        "name": "calculator",
        "description": "Realiza cálculos matemáticos",
        "input_schema": {
            "type": "object",
            "properties": {
                "expression": {
                    "type": "string",
                    "description": "Expresión matemática (ej: '2 + 2')"
                }
            },
            "required": ["expression"]
        }
    }
]

messages = [
    {"role": "user", "content": "¿Cuánto es 15 * 8?"}
]

response = client.messages.create(
    model="claude-opus-4-8",
    max_tokens=1024,
    tools=tools,
    messages=messages
)

if response.stop_reason == "tool_use":
    for content_block in response.content:
        if content_block.type == "tool_use":
            result = eval(content_block.input["expression"])
            messages.append({"role": "assistant", "content": response.content})
            messages.append({
                "role": "user",
                "content": [
                    {
                        "type": "tool_result",
                        "tool_use_id": content_block.id,
                        "content": str(result)
                    }
                ]
            })

final_response = client.messages.create(
    model="claude-opus-4-8",
    max_tokens=1024,
    tools=tools,
    messages=messages
)

print(final_response.content[0].text)

import anthropic

client = anthropic.Anthropic()

response = client.messages.count_tokens(
    model="claude-opus-4-8",
    messages=[
        {"role": "user", "content": "Hola, ¿cuántos tokens tiene este mensaje?"}
    ]
)

print(f"Tokens: {response.input_tokens}")

import anthropic
import base64

client = anthropic.Anthropic()

with open("imagen.jpg", "rb") as f:
    image_data = base64.standard_b64encode(f.read()).decode("utf-8")

message = client.messages.create(
    model="claude-opus-4-8",
    max_tokens=1024,
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "image",
                    "source": {
                        "type": "base64",
                        "media_type": "image/jpeg",
                        "data": image_data,
                    },
                },
                {
                    "type": "text",
                    "text": "¿Qué ves en esta imagen?"
                }
            ],
        }
    ],
)

print(message.content[0].text)
